import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"テイクアウト管理","description":"","frontmatter":{"title":"テイクアウト管理"},"headers":[],"relativePath":"tenant/09-takeout.md","filePath":"tenant/09-takeout.md"}'),h={name:"tenant/09-takeout.md"};function l(i,t,o,n,p,s){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="_9-テイクアウト管理" tabindex="-1">9. テイクアウト管理 <a class="header-anchor" href="#_9-テイクアウト管理" aria-label="Permalink to &quot;9. テイクアウト管理&quot;">​</a></h1><p>POSLA のテイクアウトは、店頭の注文管理とは別に「お客様の事前注文」「オンライン決済」「受取時間枠」「厨房キャパ」「梱包確認」「準備完了通知」「受取遅れ・キャンセル・返金対応」をまとめて扱うための機能です。</p><p>この章では、お店で実際に使う画面と運用手順を説明します。</p><h2 id="利用前に確認する設定" tabindex="-1">利用前に確認する設定 <a class="header-anchor" href="#利用前に確認する設定" aria-label="Permalink to &quot;利用前に確認する設定&quot;">​</a></h2><p>管理画面の設定で、テイクアウトを有効にします。</p><table tabindex="0"><thead><tr><th>設定</th><th>内容</th></tr></thead><tbody><tr><td>テイクアウト有効</td><td>お客様向けテイクアウト注文を受け付けるかどうか</td></tr><tr><td>最短準備時間</td><td>注文時点から最短で何分後の受取を許可するか</td></tr><tr><td>受付開始・受付終了</td><td>お客様が選べる受取時間帯</td></tr><tr><td>時間枠あたり最大注文数</td><td>同じ受取時間に受けられる注文数</td></tr><tr><td>時間枠あたり最大品数</td><td>同じ受取時間に受けられる合計商品数。0 の場合は品数上限なし</td></tr><tr><td>ピーク時間帯</td><td>混雑時間だけ別の注文数・品数上限を使う場合に設定</td></tr><tr><td>混雑時追加待ち時間</td><td>忙しい時間帯の受取可能時刻を遅らせるための追加時間</td></tr><tr><td>SLA警告</td><td>受取予定時刻の何分前から「遅れそう」と表示するか</td></tr><tr><td>オンライン決済</td><td>お客様が事前決済できるようにする設定</td></tr></tbody></table><p>お客様向けテイクアウト注文は、現在の実装ではオンライン決済を前提にしています。Stripe の店舗別決済設定が未完了の場合、注文画面では決済へ進めません。</p><h2 id="お客様の注文手順" tabindex="-1">お客様の注文手順 <a class="header-anchor" href="#お客様の注文手順" aria-label="Permalink to &quot;お客様の注文手順&quot;">​</a></h2><ol><li>お客様がテイクアウト注文画面を開きます。</li><li>商品を選びます。</li><li>名前・電話番号・受取時刻・必要に応じてメモを入力します。</li><li>受取時間を選択します。</li><li>オンライン決済に進みます。</li><li>決済完了後、注文詳細画面で注文状況を確認できます。</li></ol><p>受取時間は、店舗の受付時間・最短準備時間・時間枠上限・ピーク時間設定・既存注文数をもとに自動判定されます。上限に達している時間帯は、お客様が選べない状態になります。</p><h2 id="再注文候補" tabindex="-1">再注文候補 <a class="header-anchor" href="#再注文候補" aria-label="Permalink to &quot;再注文候補&quot;">​</a></h2><p>お客様が同じ端末で名前・電話番号を入力すると、過去のテイクアウト注文から再注文候補を表示できます。</p><p>再注文候補は、次の条件を満たすものだけが対象です。</p><table tabindex="0"><thead><tr><th>条件</th><th>内容</th></tr></thead><tbody><tr><td>同じ店舗</td><td>別店舗の注文は表示されません</td></tr><tr><td>電話番号一致</td><td>入力された電話番号で過去注文を検索します</td></tr><tr><td>完了済み注文</td><td>準備完了・受渡済み・会計済みの注文が候補になります</td></tr><tr><td>現在販売中の商品</td><td>現在のメニューに存在し、売り切れではない商品だけを再追加します</td></tr></tbody></table><p>過去に注文した商品でも、現在メニューにない商品や売り切れの商品は再注文に含まれません。</p><h2 id="受取前の状況確認" tabindex="-1">受取前の状況確認 <a class="header-anchor" href="#受取前の状況確認" aria-label="Permalink to &quot;受取前の状況確認&quot;">​</a></h2><p>お客様は注文詳細画面で、次の内容を確認できます。</p><table tabindex="0"><thead><tr><th>表示</th><th>内容</th></tr></thead><tbody><tr><td>注文状態</td><td>支払待ち、受付済み、調理中、準備完了、受渡済みなど</td></tr><tr><td>受取予定時刻</td><td>注文時に選んだ受取時刻</td></tr><tr><td>注文内容</td><td>商品名、数量、金額</td></tr><tr><td>受取到着連絡</td><td>店頭到着または車内待機を店舗へ知らせる操作</td></tr><tr><td>LINE連携案内</td><td>店舗側の LINE 連携が有効な場合に表示</td></tr></tbody></table><p>受取到着連絡では「店頭に着きました」「車で待っています」を選べます。メモも入力できます。キャンセル済み・受渡済み・会計済みの注文では、到着連絡はできません。</p><h2 id="店舗側のテイクアウト管理" tabindex="-1">店舗側のテイクアウト管理 <a class="header-anchor" href="#店舗側のテイクアウト管理" aria-label="Permalink to &quot;店舗側のテイクアウト管理&quot;">​</a></h2><p>店舗側では、テイクアウト管理画面で当日の注文を確認します。</p><p>上部には、次の集計が表示されます。</p><table tabindex="0"><thead><tr><th>集計</th><th>内容</th></tr></thead><tbody><tr><td>本日の注文数</td><td>表示対象日のテイクアウト注文数</td></tr><tr><td>SLA警告</td><td>受取予定時刻が近く、遅れそうな注文</td></tr><tr><td>遅延中</td><td>受取予定時刻を過ぎても完了していない注文</td></tr><tr><td>梱包未完了</td><td>梱包チェックが完了していない注文</td></tr><tr><td>通知失敗</td><td>準備完了通知の送信に失敗した注文</td></tr><tr><td>返金対応</td><td>キャンセル・返金対応が必要な注文</td></tr><tr><td>到着待機</td><td>お客様から到着連絡が入っている注文</td></tr></tbody></table><p>管理画面の <strong>運営管理 → 運営コックピット</strong> にも、テイクアウト遅延リスクが表示されます。受取時刻が近い未完了注文がある場合は、テイクアウト管理を開いて、調理、梱包、通知、受け渡しを確認してください。</p><h2 id="店舗側の表示とフィルター" tabindex="-1">店舗側の表示とフィルター <a class="header-anchor" href="#店舗側の表示とフィルター" aria-label="Permalink to &quot;店舗側の表示とフィルター&quot;">​</a></h2><p>テイクアウト管理では、注文状態や運用状態を見ながら、受取時刻順に対応します。</p><p>主な見方:</p><table tabindex="0"><thead><tr><th>見る場所</th><th>内容</th></tr></thead><tbody><tr><td>上部KPI</td><td>本日の注文、SLA警告、遅延中、梱包未完了、通知失敗、返金対応、到着待機</td></tr><tr><td>注文カード</td><td>受取時刻、注文者、電話番号、商品、合計、支払い、メモ</td></tr><tr><td>ステータス操作</td><td>受付済み、調理中、準備完了、受渡済みへ進める</td></tr><tr><td>梱包チェック</td><td>商品、箸、袋、ソース、領収書の確認</td></tr><tr><td>通知状態</td><td>未送信、送信済み、送信失敗、スキップ</td></tr><tr><td>運用ステータス</td><td>遅延リスク、お客様遅れ、キャンセル依頼、返金待ちなど</td></tr></tbody></table><p>準備完了にした注文は、お客様へ受け渡すまで <strong>準備完了</strong> のまま残ります。受け渡し後は <strong>受渡済み</strong> にしてください。準備完了のまま閉店すると、閉店前チェックで確認対象になります。</p><h2 id="注文ステータス" tabindex="-1">注文ステータス <a class="header-anchor" href="#注文ステータス" aria-label="Permalink to &quot;注文ステータス&quot;">​</a></h2><p>店舗側の主なステータス遷移は次の通りです。</p><table tabindex="0"><thead><tr><th>現在</th><th>次に進める状態</th><th>主な操作</th></tr></thead><tbody><tr><td>支払待ち</td><td>受付済み、キャンセル</td><td>決済後の受付、またはキャンセル</td></tr><tr><td>受付済み</td><td>調理中</td><td>調理開始</td></tr><tr><td>調理中</td><td>準備完了</td><td>商品完成</td></tr><tr><td>準備完了</td><td>受渡済み</td><td>お客様へ受け渡し</td></tr></tbody></table><p>準備完了にすると、店舗の LINE 連携設定とお客様の LINE 紐付け状態に応じて、準備完了通知が送信されます。送信できなかった場合は、管理画面に失敗として表示されます。</p><h2 id="梱包チェックリスト" tabindex="-1">梱包チェックリスト <a class="header-anchor" href="#梱包チェックリスト" aria-label="Permalink to &quot;梱包チェックリスト&quot;">​</a></h2><p>注文ごとに、次の梱包チェックを確認します。</p><table tabindex="0"><thead><tr><th>チェック</th><th>内容</th></tr></thead><tbody><tr><td>商品</td><td>注文商品が揃っているか</td></tr><tr><td>箸</td><td>必要な箸・カトラリーが入っているか</td></tr><tr><td>袋</td><td>袋に入っているか</td></tr><tr><td>ソース</td><td>ソース・調味料が揃っているか</td></tr><tr><td>領収書</td><td>領収書が必要な場合に入っているか</td></tr></tbody></table><p>すべてにチェックが入ると、梱包完了として扱われます。</p><h2 id="運用ステータス" tabindex="-1">運用ステータス <a class="header-anchor" href="#運用ステータス" aria-label="Permalink to &quot;運用ステータス&quot;">​</a></h2><p>注文ステータスとは別に、店舗内部の対応状況を管理できます。</p><table tabindex="0"><thead><tr><th>ステータス</th><th>用途</th></tr></thead><tbody><tr><td>通常</td><td>特別対応なし</td></tr><tr><td>遅延リスク</td><td>遅れそうな注文</td></tr><tr><td>遅延中</td><td>受取予定時刻を過ぎている注文</td></tr><tr><td>お客様遅れ</td><td>お客様がまだ来店していない注文</td></tr><tr><td>キャンセル依頼</td><td>キャンセル相談・依頼中</td></tr><tr><td>キャンセル済み</td><td>キャンセル処理済み</td></tr><tr><td>返金待ち</td><td>返金確認が必要</td></tr><tr><td>返金済み</td><td>返金対応済み</td></tr></tbody></table><p>キャンセル済みにすると、受渡済み・会計済みでない注文はキャンセル状態になります。返金そのものは決済事業者側の処理も確認してください。</p><h2 id="準備完了通知" tabindex="-1">準備完了通知 <a class="header-anchor" href="#準備完了通知" aria-label="Permalink to &quot;準備完了通知&quot;">​</a></h2><p>準備完了通知は、注文を「準備完了」にしたタイミングで送信されます。店舗側から再送操作もできます。</p><p>通知状態は次のいずれかで表示されます。</p><table tabindex="0"><thead><tr><th>表示</th><th>意味</th></tr></thead><tbody><tr><td>未送信</td><td>まだ通知していません</td></tr><tr><td>送信済み</td><td>通知送信に成功しました</td></tr><tr><td>送信失敗</td><td>通知送信に失敗しました</td></tr><tr><td>スキップ</td><td>LINE連携やお客様の紐付けがなく、送信対象外です</td></tr></tbody></table><p>現在のテイクアウト準備完了通知は LINE 連携を前提にしています。SMS通知はテイクアウトの標準機能としては実装されていません。</p><p>LINE連携が未設定、またはお客様が注文とLINEを紐付けていない場合、通知状態はスキップまたは失敗として表示されます。この場合は、電話など店舗の通常連絡手段で連絡してください。</p><h2 id="誤会計の取消とオンライン決済返金" tabindex="-1">誤会計の取消とオンライン決済返金 <a class="header-anchor" href="#誤会計の取消とオンライン決済返金" aria-label="Permalink to &quot;誤会計の取消とオンライン決済返金&quot;">​</a></h2><p>POS レジでゲートウェイを経由せずに会計したテイクアウトは、POS レジ側の取引ジャーナルから会計取消できる場合があります。現金、手動 card、手動 qr など、ゲートウェイ非経由の会計が対象です。</p><p>オンライン決済済みのテイクアウト注文で誤会計やキャンセルが発生した場合は、会計取消ではなく返金対応になります。POSLA の運用ステータスで「返金待ち」「返金済み」を管理し、決済事業者側の返金状態も確認してください。</p><h2 id="受取遅れ・キャンセル・返金対応" tabindex="-1">受取遅れ・キャンセル・返金対応 <a class="header-anchor" href="#受取遅れ・キャンセル・返金対応" aria-label="Permalink to &quot;受取遅れ・キャンセル・返金対応&quot;">​</a></h2><p>遅れそうな注文は SLA警告として表示されます。受取予定時刻を過ぎても準備完了または受渡済みになっていない場合は、遅延中として扱われます。</p><p>キャンセルや返金が必要な場合は、運用ステータスを「キャンセル依頼」「キャンセル済み」「返金待ち」「返金済み」に変更して、対応状況を残します。オンライン決済の返金は、POSLA 上の表示だけで完了するものではありません。決済管理画面または決済連携側の返金状態も確認してください。</p><h2 id="お客様画面でのエラー表示" tabindex="-1">お客様画面でのエラー表示 <a class="header-anchor" href="#お客様画面でのエラー表示" aria-label="Permalink to &quot;お客様画面でのエラー表示&quot;">​</a></h2><p>Stripe 決済が完了したのに、POSLA 側で注文の記録に失敗したごく稀なケースでは、お客様の画面に次の内容が表示されます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>決済確認に失敗しました</span></span>
<span class="line"><span>決済は Stripe 側で完了している可能性があります。</span></span>
<span class="line"><span>お手数ですが、下記の注文番号を添えて店舗まで直接お問い合わせください。</span></span>
<span class="line"><span>注文番号: XXXXXXXX</span></span></code></pre></div><p>この場合は、注文番号と発生時刻を POSLA サポートへ共有し、店舗側でも同じ時間帯の注文一覧と決済状況を確認してください。</p><h2 id="閉店前チェック" tabindex="-1">閉店前チェック <a class="header-anchor" href="#閉店前チェック" aria-label="Permalink to &quot;閉店前チェック&quot;">​</a></h2><p>営業終了前に、次を確認します。</p><ul><li>準備完了のまま受渡済みになっていない注文が残っていないか</li><li>梱包未完了の注文がないか</li><li>通知失敗の注文に電話などで連絡済みか</li><li>キャンセル依頼・返金待ちの注文が残っていないか</li><li>到着連絡がある注文を見落としていないか</li></ul><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>困ったこと</th><th>確認すること</th></tr></thead><tbody><tr><td>お客様が注文できない</td><td>テイクアウト有効、受付時間、オンライン決済設定、売り切れ商品を確認</td></tr><tr><td>受取時間が表示されない</td><td>最短準備時間、時間枠上限、ピーク上限、受付時間を確認</td></tr><tr><td>準備完了通知が届かない</td><td>店舗の LINE 設定、お客様の LINE 紐付け、通知失敗表示を確認</td></tr><tr><td>再注文に商品が出ない</td><td>現在のメニューに商品があるか、売り切れでないかを確認</td></tr><tr><td>返金済みか分からない</td><td>POSLA の運用ステータスと決済事業者側の返金状態を両方確認</td></tr><tr><td>注文を停止したい</td><td>テイクアウト設定を無効にし、案内QRの掲示も確認</td></tr></tbody></table>`,62)])])}const u=d(h,[["render",l]]);export{c as __pageData,u as default};
